#!/usr/bin/env python3
"""
Patch script for Sarang's portfolio — adds Databricks project.
Run: python3 patch.py index.html > index_new.html
Then rename index_new.html to index.html
"""
import sys

if len(sys.argv) < 2:
    print("Usage: python3 patch.py index.html > index_new.html")
    sys.exit(1)

with open(sys.argv[1], encoding='utf-8') as f:
    html = f.read()

# ── PATCH 1: Databricks card after CrowdPulse in ML section ──
CARD = """    <div class="pc cgr" onclick="openOv('databricks')">
      <div class="pt">Databricks · Medallion Architecture · MLflow · Delta Lake · Unity Catalog</div>
      <div class="pn">Fraud Detection Pipeline</div>
      <div class="ph">0.9585 ROC-AUC — end-to-end Bronze → Silver → Gold → ML in 18 minutes</div>
      <p class="pd">Auto Loader ingestion → PySpark Medallion transforms → GradientBoosting with MLflow tracking → Unity Catalog model registry → batch scoring. 284,807 transactions, 0.17% fraud rate. All 4 tasks orchestrated as a single Databricks Job.</p>
      <div class="pills"><span class="pill">Databricks</span><span class="pill">Delta Lake</span><span class="pill">MLflow</span></div>
      <div class="plink">Open Case Study →</div>
    </div>"""

target = "      <div class=\"plink\">Open Case Study →</div>\n    </div>\n  </div>\n</section>\n\n<!-- BUSINESS MODELING"
replacement = f"      <div class=\"plink\">Open Case Study →</div>\n    </div>\n{CARD}\n  </div>\n</section>\n\n<!-- BUSINESS MODELING"
if target in html:
    html = html.replace(target, replacement, 1)
    print("✓ Databricks card added", file=sys.stderr)
else:
    print("✗ Card insertion point not found", file=sys.stderr)

# ── PATCH 2: routeMap entry ──
old_route = "  'kl-worldwide': 'klworldwide'"
new_route = "  'kl-worldwide': 'klworldwide',\n  'databricks': 'databricks'"
if old_route in html:
    html = html.replace(old_route, new_route, 1)
    print("✓ routeMap entry added", file=sys.stderr)
else:
    print("✗ routeMap entry not found", file=sys.stderr)

# ── PATCH 3: Databricks overlay before </body> ──
OVERLAY = '<!-- ════════ DATABRICKS FRAUD DETECTION ════════ -->\n<div id="ov-databricks" class="ov">\n<button class="cbtn" onclick="closeOv()">← Back</button>\n<div class="oh" style="background:linear-gradient(155deg,#001a18 0%,#080808 60%)">\n  <div class="otag" style="color:var(--gr)">Databricks · Medallion Architecture · MLflow · Delta Lake · Unity Catalog</div>\n  <div class="oname">Fraud Detection Pipeline</div>\n  <div class="ohead">End-to-end Bronze → Silver → Gold → ML pipeline on Databricks. 284,807 transactions, 18-minute full run, 0.9585 ROC-AUC — production-grade architecture from ingestion to model registry.</div>\n  <div class="omets">\n    <div class="omet"><div class="omn" style="color:var(--gr)">0.9585</div><div class="oml">ROC-AUC</div></div>\n    <div class="omet"><div class="omn" style="color:var(--g)">81.05%</div><div class="oml">Recall (Fraud)</div></div>\n    <div class="omet"><div class="omn" style="color:var(--w)">284,807</div><div class="oml">Transactions</div></div>\n    <div class="omet"><div class="omn" style="color:var(--r)">18 min</div><div class="oml">Full Pipeline Runtime</div></div>\n    <div class="omet"><div class="omn" style="color:var(--b)">4</div><div class="oml">Orchestrated Tasks</div></div>\n  </div>\n</div>\n<div class="obody">\n  <div class="osec">\n    <div class="ostag">The Problem</div>\n    <div class="ostit">0.17% Fraud Rate — The Architecture Problem Is Harder Than the Model</div>\n    <div class="otxt">\n      <p>The Kaggle Credit Card Fraud dataset is a canonical imbalance problem — 284,807 transactions, 492 fraud cases, 0.17% positive class. Most approaches treat this as a pure modeling problem and stop at a trained classifier. The harder and more production-relevant challenge is building the <strong>infrastructure that gets data from raw CSV to a registered, versioned model serving batch predictions</strong> — reliably, incrementally, and with full lineage.</p>\n      <p>This project implements that infrastructure end-to-end on Databricks: Auto Loader ingestion, Medallion Architecture with Delta Lake, MLflow experiment tracking, Unity Catalog model registry, and Databricks Jobs orchestration. The result is not just a model — it is a reproducible, auditable ML pipeline.</p>\n    </div>\n  </div>\n  <div class="osec">\n    <div class="ostag">Architecture</div>\n    <div class="ostit">Medallion Architecture: Bronze → Silver → Gold → ML</div>\n    <div class="otxt"><p>The Medallion Architecture separates raw ingestion, data quality, feature engineering, and ML into distinct layers — each a Delta table with full history, schema enforcement, and ACID guarantees. Each layer has a single responsibility and fails independently without corrupting upstream data.</p></div>\n    <div class="flow">\n      <div class="fstep"><div class="fsn">Raw</div><div class="fsname">CSV in Databricks Volume</div></div>\n      <div class="farr">→</div>\n      <div class="fstep"><div class="fsn">Bronze</div><div class="fsname">Auto Loader → Delta (284,807 rows)</div></div>\n      <div class="farr">→</div>\n      <div class="fstep"><div class="fsn">Silver</div><div class="fsname">Quality Filters (283,726 rows)</div></div>\n      <div class="farr">→</div>\n      <div class="fstep"><div class="fsn">Gold</div><div class="fsname">Feature Engineering (model-ready)</div></div>\n      <div class="farr">→</div>\n      <div class="fstep"><div class="fsn">ML</div><div class="fsname">MLflow → Unity Catalog Registry</div></div>\n      <div class="farr">→</div>\n      <div class="fstep"><div class="fsn">Scored</div><div class="fsname">fraud_scored Delta Table</div></div>\n    </div>\n    <table class="ctbl">\n      <thead><tr><th>Layer</th><th>Rows</th><th>Key Operations</th><th>Storage</th></tr></thead>\n      <tbody>\n        <tr><td>Bronze</td><td>284,807</td><td>Auto Loader cloudFiles ingestion, schema inference, checkpoint</td><td>Delta — full raw history preserved</td></tr>\n        <tr class="hlrow"><td>Silver</td><td>283,726</td><td>Type casting, quality constraints, deduplication, null removal</td><td>Delta — 1,081 rows dropped by quality rules</td></tr>\n        <tr><td>Gold</td><td>283,726</td><td>Amount_log, Amount_scaled, high_value flag, Time dropped</td><td>Delta — model-ready feature table</td></tr>\n        <tr><td>Scored</td><td>283,726</td><td>Fraud probability + binary prediction from Registry model</td><td>Delta — full predictions with lineage</td></tr>\n      </tbody>\n    </table>\n  </div>\n  <div class="osec">\n    <div class="ostag">Task 1 — Bronze Layer</div>\n    <div class="ostit">Auto Loader: Incremental Ingestion With Schema Evolution</div>\n    <div class="otxt">\n      <p>Bronze ingestion uses Databricks Auto Loader (<code>cloudFiles</code> format) with <code>trigger(availableNow=True)</code> — batch-style incremental processing that picks up only new files since the last checkpoint. Schema inference runs once and checkpoints for evolution. Raw data lands in <code>fraud_bronze</code> as a Delta table with full history and no transformations — the bronze layer is intentionally a faithful copy of the source.</p>\n      <p>This design means the pipeline can be re-run without re-ingesting data that was already processed. If new transactions arrive tomorrow, Auto Loader detects the new files and processes only the delta — the rest of the pipeline runs unchanged.</p>\n    </div>\n    <div class="insight">Auto Loader\'s cloudFiles format internally uses file notification or directory listing to detect new files. The checkpoint stores which files have been processed, making the bronze layer idempotent — running the notebook twice does not duplicate data.</div>\n  </div>\n  <div class="osec">\n    <div class="ostag">Task 2 — Silver &amp; Gold Layers</div>\n    <div class="ostit">Data Quality Enforcement + Feature Engineering in PySpark</div>\n    <div class="otxt">\n      <p><strong>Silver layer</strong> enforces four quality constraints on the raw data: Amount must be ≥ 0 (no negative transactions), Class must be 0 or 1 (no invalid labels), key columns must be non-null, and duplicates are removed. 1,081 records — 0.38% of the dataset — failed quality rules and were dropped. The Silver table documents exactly which records failed and why via Delta Lake\'s transaction log.</p>\n      <p><strong>Gold layer</strong> engineers three features and removes one. <code>Amount_log</code> applies log1p scaling to normalize the heavily right-skewed transaction amount distribution. <code>Amount_scaled</code> normalizes to 0–1 range. <code>high_value</code> is a binary flag for transactions above $1,000. The raw <code>Time</code> column is dropped — as a sequential transaction counter it encodes dataset order, not behavioral signal.</p>\n    </div>\n    <table class="ctbl">\n      <thead><tr><th>Feature</th><th>Type</th><th>Rationale</th></tr></thead>\n      <tbody>\n        <tr><td>Amount_log</td><td>Engineered</td><td>log1p normalization — transaction amounts are power-law distributed; log stabilizes variance</td></tr>\n        <tr class="hlrow"><td>Amount_scaled</td><td>Engineered</td><td>0–1 normalization for gradient-based model convergence</td></tr>\n        <tr><td>high_value</td><td>Binary flag</td><td>Transactions &gt;$1,000 have structurally different fraud patterns</td></tr>\n        <tr><td>Time</td><td>Dropped</td><td>Sequential index — not predictive; encodes dataset order not transaction timing</td></tr>\n      </tbody>\n    </table>\n  </div>\n  <div class="osec">\n    <div class="ostag">Task 3 — Model Training</div>\n    <div class="ostit">MLflow Experiment Tracking + Unity Catalog Model Registry</div>\n    <div class="otxt">\n      <p>Training uses a scikit-learn <code>Pipeline</code> — <code>SimpleImputer(strategy="median")</code> followed by <code>GradientBoostingClassifier</code>. Class imbalance is handled via <code>compute_sample_weight(class_weight="balanced")</code>, which assigns each fraud transaction a weight of ~576x relative to a legitimate transaction. This is computationally equivalent to SMOTE oversampling but without creating synthetic samples.</p>\n      <p>All parameters, metrics, model artifact, and input/output signature are logged to MLflow automatically. The trained model is registered to Unity Catalog as <code>workspace.default.fraud_classifier</code> version 1 — making it discoverable, versionable, and loadable by any downstream task via the Registry URI.</p>\n    </div>\n    <div class="rgrid">\n      <div class="rcard"><div class="rn" style="color:var(--gr)">0.9585</div><div class="rl">ROC-AUC — strong discrimination between fraud and legitimate across all thresholds</div></div>\n      <div class="rcard"><div class="rn" style="color:var(--g)">81.05%</div><div class="rl">Recall — catches 4 in 5 actual fraud cases; prioritized over precision by design</div></div>\n      <div class="rcard"><div class="rn" style="color:var(--b)">0.7794</div><div class="rl">Average Precision — area under precision-recall curve; robust to class imbalance</div></div>\n      <div class="rcard"><div class="rn" style="color:var(--w)">0.7097</div><div class="rl">F1 Score — harmonic mean of precision (63.1%) and recall (81.05%)</div></div>\n    </div>\n    <div class="insight">Recall is the right metric to prioritize in fraud detection. A false negative — missing actual fraud — costs the bank the full fraudulent transaction amount. A false positive — flagging a legitimate transaction — costs a customer service interaction. The asymmetry justifies optimizing for recall over precision.</div>\n  </div>\n  <div class="osec">\n    <div class="ostag">Task 4 — Batch Scoring</div>\n    <div class="ostit">Model Loaded From Registry — Scores Full Gold Table Back to Delta</div>\n    <div class="otxt">\n      <p>Batch scoring loads the model directly from Unity Catalog using the Registry URI: <code>models:/workspace.default.fraud_classifier/1</code>. No model artifact is embedded in the scoring notebook — it resolves at runtime from the Registry, meaning a model upgrade only requires bumping the version number. The full Gold table (283,726 rows) is scored, producing fraud probability and binary prediction for every transaction, written back to <code>fraud_scored</code> Delta table.</p>\n      <p>This pattern — train once, score many times from registry — is the production pattern. It decouples model development from model serving and creates a clean audit trail of which model version scored which data.</p>\n    </div>\n  </div>\n  <div class="osec">\n    <div class="ostag">Orchestration</div>\n    <div class="ostit">Single Databricks Job — 4 Sequential Tasks, 18 Minutes Total</div>\n    <div class="otxt"><p>All four notebooks are wired as a single Databricks Job with sequential task dependencies: bronze → silver_gold → training → scoring. Task 2 cannot start until Task 1 completes successfully. Task 3 cannot start until Task 2 writes a valid Gold table. This dependency graph prevents partial pipeline runs from corrupting downstream tables.</p></div>\n    <table class="ctbl">\n      <thead><tr><th>Task</th><th>Notebook</th><th>Status</th><th>Duration</th></tr></thead>\n      <tbody>\n        <tr class="hlrow"><td>bronze_ingestion</td><td>01_bronze_autoloader.py</td><td>Succeeded ✓</td><td>~34s</td></tr>\n        <tr><td>silver_gold_transform</td><td>02_silver_gold_batch.py</td><td>Succeeded ✓</td><td>~1m</td></tr>\n        <tr class="hlrow"><td>model_training</td><td>03_model_training.py</td><td>Succeeded ✓</td><td>~15m</td></tr>\n        <tr><td>batch_scoring</td><td>04_batch_scoring.py</td><td>Succeeded ✓</td><td>~3m</td></tr>\n      </tbody>\n    </table>\n    <div class="insight">15 of the 18 minutes are consumed by model training on Databricks Serverless compute. The data engineering tasks (ingestion + transforms + scoring) complete in under 4 minutes combined, demonstrating the efficiency of the PySpark + Delta Lake stack.</div>\n  </div>\n  <div class="osec">\n    <div class="ostag">Screenshots</div>\n    <div class="ostit">Pipeline Run · MLflow · Delta Tables · Model Registry</div>\n    <div style="display:grid;grid-template-columns:1fr 1fr;gap:2px;margin:20px 0">\n      <div style="background:var(--m);border:1px solid var(--bd);overflow:hidden">\n        <img src="https://raw.githubusercontent.com/SarrangTech/fraud-detection-databricks/main/screenshots/pipeline_run.png" alt="Databricks Job — all 4 tasks green" style="width:100%;display:block;filter:brightness(0.92)" onerror="this.parentElement.innerHTML=\'<div style=&quot;padding:32px;font-family:DM Mono,monospace;font-size:10px;color:var(--mu);letter-spacing:.1em;text-transform:uppercase&quot;>Pipeline run screenshot — github.com/SarrangTech/fraud-detection-databricks</div>\'">\n        <div style="padding:10px 14px;font-family:\'DM Mono\',monospace;font-size:9px;letter-spacing:.12em;text-transform:uppercase;color:var(--mu)">Databricks Job — all 4 tasks succeeded</div>\n      </div>\n      <div style="background:var(--m);border:1px solid var(--bd);overflow:hidden">\n        <img src="https://raw.githubusercontent.com/SarrangTech/fraud-detection-databricks/main/screenshots/mlflow_experiments.png" alt="MLflow experiment runs" style="width:100%;display:block;filter:brightness(0.92)" onerror="this.parentElement.innerHTML=\'<div style=&quot;padding:32px;font-family:DM Mono,monospace;font-size:10px;color:var(--mu);letter-spacing:.1em;text-transform:uppercase&quot;>MLflow experiments screenshot</div>\'">\n        <div style="padding:10px 14px;font-family:\'DM Mono\',monospace;font-size:9px;letter-spacing:.12em;text-transform:uppercase;color:var(--mu)">MLflow experiment runs — metrics logged</div>\n      </div>\n      <div style="background:var(--m);border:1px solid var(--bd);overflow:hidden">\n        <img src="https://raw.githubusercontent.com/SarrangTech/fraud-detection-databricks/main/screenshots/delta_tables.png" alt="Unity Catalog Delta tables" style="width:100%;display:block;filter:brightness(0.92)" onerror="this.parentElement.innerHTML=\'<div style=&quot;padding:32px;font-family:DM Mono,monospace;font-size:10px;color:var(--mu);letter-spacing:.1em;text-transform:uppercase&quot;>Delta tables screenshot</div>\'">\n        <div style="padding:10px 14px;font-family:\'DM Mono\',monospace;font-size:9px;letter-spacing:.12em;text-transform:uppercase;color:var(--mu)">Unity Catalog — Bronze, Silver, Gold, Scored tables</div>\n      </div>\n      <div style="background:var(--m);border:1px solid var(--bd);overflow:hidden">\n        <img src="https://raw.githubusercontent.com/SarrangTech/fraud-detection-databricks/main/screenshots/model_registry.png" alt="Unity Catalog Model Registry" style="width:100%;display:block;filter:brightness(0.92)" onerror="this.parentElement.innerHTML=\'<div style=&quot;padding:32px;font-family:DM Mono,monospace;font-size:10px;color:var(--mu);letter-spacing:.1em;text-transform:uppercase&quot;>Model registry screenshot</div>\'">\n        <div style="padding:10px 14px;font-family:\'DM Mono\',monospace;font-size:9px;letter-spacing:.12em;text-transform:uppercase;color:var(--mu)">fraud_classifier v1 — Unity Catalog Model Registry</div>\n      </div>\n    </div>\n  </div>\n  <div class="osec">\n    <div class="ostag">Why This Architecture Matters</div>\n    <div class="ostit">Three Production Properties Most Portfolios Don\'t Have</div>\n    <div class="otxt">\n      <p><strong>Incremental by design.</strong> Auto Loader + checkpointing means the pipeline processes only new data on each run. In production, this translates to running hourly or daily without re-scanning the full dataset. Most portfolio projects rebuild from scratch on every run.</p>\n      <p><strong>Auditable by design.</strong> Delta Lake\'s transaction log records every write, schema change, and quality filter. You can time-travel to any version of any table. Unity Catalog records which model version scored which data. In a regulated financial environment, this audit trail is not optional.</p>\n      <p><strong>Decoupled by design.</strong> The model is registered in Unity Catalog, not embedded in the scoring notebook. Upgrading the model means registering a new version and bumping a number — the scoring pipeline is unchanged. This is the production pattern. Hardcoding model artifacts into scoring notebooks is the notebook pattern.</p>\n    </div>\n  </div>\n  <div class="osec">\n    <div class="ostag">Stack</div><div class="ostit">Built With</div>\n    <div class="tools">\n      <span class="ttag">Databricks Community Edition</span>\n      <span class="ttag">PySpark</span>\n      <span class="ttag">Delta Lake</span>\n      <span class="ttag">Auto Loader (cloudFiles)</span>\n      <span class="ttag">MLflow</span>\n      <span class="ttag">Unity Catalog</span>\n      <span class="ttag">Databricks Jobs</span>\n      <span class="ttag">GradientBoostingClassifier</span>\n      <span class="ttag">scikit-learn Pipeline</span>\n      <span class="ttag">Sample Weights (balanced)</span>\n      <span class="ttag">Python 3.12</span>\n    </div>\n    <div class="olinks">\n      <a href="https://github.com/SarrangTech/fraud-detection-databricks" class="olink pri" target="_blank">GitHub →</a>\n    </div>\n  </div>\n</div>\n</div>'
if "</body>" in html:
    html = html.replace("</body>", OVERLAY + "\n</body>", 1)
    print("✓ Databricks overlay added", file=sys.stderr)
else:
    print("✗ </body> not found", file=sys.stderr)

print(html, end="")
